#nullable enable // autogenerated

using System.Collections.Generic;
using System.Xml;
using MVZ2.IO;
using MVZ2Logic.Options;
using PVZEngine;

namespace MVZ2.Metas
{
    public class OptionWidgetMeta
    {
        public OptionWidgetType Type { get; private set; }
        public string ID { get; private set; }
        public NamespaceID Category { get; private set; }
        public string Label { get; private set; } = string.Empty;
        public string Tooltip { get; private set; } = string.Empty;

        public OptionWidgetMeta(OptionWidgetType type, string iD, NamespaceID category)
        {
            Type = type;
            ID = iD;
            Category = category;
        }
        public static OptionWidgetMeta? FromXmlNode(XmlNode node, string defaultNsp)
        {
            var id = node.GetAttribute("id");
            if (string.IsNullOrEmpty(id))
            {
                Log.LogError($"The {nameof(id)} of a {nameof(OptionWidgetMeta)} is invalid.");
                return null;
            }
            var category = node.GetAttributeNamespaceID("category", defaultNsp);
            if (!NamespaceID.IsValid(category))
            {
                Log.LogError($"The {nameof(category)} of a {nameof(OptionWidgetMeta)} is invalid.");
                return null;
            }
            var label = node.GetAttribute("label") ?? string.Empty;
            var tooltipNode = node["tooltip"];
            var tooltip = string.Empty;
            if (tooltipNode != null)
            {
                tooltip = tooltipNode.ConcatNodeParagraphs();
            }
            OptionWidgetType type = OptionWidgetType.Button;
            if (typeDict.TryGetValue(node.Name, out var t))
            {
                type = t;
            }
            return new OptionWidgetMeta(type, id, category)
            {
                Label = label,
                Tooltip = tooltip,
            };
        }
        private static readonly Dictionary<string, OptionWidgetType> typeDict = new Dictionary<string, OptionWidgetType>()
        {
            { "button", OptionWidgetType.Button },
            { "toggle", OptionWidgetType.Toggle },
            { "dropdown", OptionWidgetType.Dropdown },
            { "slider", OptionWidgetType.Slider },
        };
    }
}
